module mux8to1 (
    input [2:0] sel,
    input [7:0] in0,
    input [7:0] in1,
    input [7:0] in2,
    input [7:0] in3,
    input [7:0] in4,
    input [7:0] in5,
    input [7:0] in6,
    input [7:0] in7,
    output [7:0] out
);

    reg [7:0] unused_mux_out;  // Multiplexer output register

    always @(*) begin
        case (sel)
            3'b000: unused_mux_out = in0;
            3'b001: unused_mux_out = in1;
            3'b010: unused_mux_out = in2;
            3'b011: unused_mux_out = in3;
            3'b100: unused_mux_out = in4;
            3'b101: unused_mux_out = in5;
            3'b110: unused_mux_out = in6;
            3'b111: unused_mux_out = in7;
            default: unused_mux_out = 8'b00000000;  // Default case (should not occur)
        endcase
    end

    assign out = unused_mux_out;

endmodule
